import re
import boto3
from urllib.parse import urlparse
from botocore.exceptions import ClientError
import ipaddress
import socket


# Allowlist of permitted domains for webhook endpoints
ALLOWED_DOMAINS = [
    "hooks.example.com",
    "webhooks.yourdomain.com",
    # Add your trusted webhook domains here
]

BLOCKED_IP_RANGES = [
    ipaddress.ip_network("10.0.0.0/8"),
    ipaddress.ip_network("172.16.0.0/12"),
    ipaddress.ip_network("192.168.0.0/16"),
    ipaddress.ip_network("127.0.0.0/8"),
    ipaddress.ip_network("169.254.0.0/16"),  # AWS metadata endpoint range
    ipaddress.ip_network("fd00::/8"),
    ipaddress.ip_network("::1/128"),
]


def validate_endpoint_url(url: str) -> tuple[bool, str]:
    """Validate that the endpoint URL is safe and allowed."""
    # Check URL format
    try:
        parsed = urlparse(url)
    except Exception:
        return False, "Invalid URL format."

    # Enforce HTTPS only
    if parsed.scheme != "https":
        return False, "Only HTTPS endpoints are allowed."

    # Ensure hostname is present
    hostname = parsed.hostname
    if not hostname:
        return False, "URL must contain a valid hostname."

    # Check against domain allowlist
    domain_allowed = False
    for allowed_domain in ALLOWED_DOMAINS:
        if hostname == allowed_domain or hostname.endswith(f".{allowed_domain}"):
            domain_allowed = True
            break

    if not domain_allowed:
        return False, (
            f"Domain '{hostname}' is not in the allowed domains list. "
            f"Allowed: {ALLOWED_DOMAINS}"
        )

    # Resolve hostname and check for private/internal IPs (SSRF protection)
    try:
        resolved_ips = socket.getaddrinfo(hostname, None)
        for entry in resolved_ips:
            ip = ipaddress.ip_address(entry[4][0])
            for blocked_range in BLOCKED_IP_RANGES:
                if ip in blocked_range:
                    return False, (
                        f"Endpoint resolves to a private/internal IP address "
                        f"({ip}), which is not allowed."
                    )
    except socket.gaierror:
        return False, f"Could not resolve hostname '{hostname}'."

    # Block URLs with credentials embedded
    if parsed.username or parsed.password:
        return False, "URLs with embedded credentials are not allowed."

    # Basic path traversal check
    if ".." in parsed.path:
        return False, "Path traversal patterns are not allowed in the URL."

    return True, "Validation passed."


def create_sns_subscription(topic_arn: str, endpoint_url: str) -> dict | None:
    """Create an SNS subscription with a validated endpoint."""
    # Validate the topic ARN format
    arn_pattern = r"^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+$"
    if not re.match(arn_pattern, topic_arn):
        print(f"Error: Invalid SNS Topic ARN format: {topic_arn}")
        return None

    # Validate the endpoint URL
    is_valid, message = validate_endpoint_url(endpoint_url)
    if not is_valid:
        print(f"Error: Endpoint validation failed — {message}")
        return None

    # Create the subscription
    sns_client = boto3.client("sns")
    try:
        response = sns_client.subscribe(
            TopicArn=topic_arn,
            Protocol="https",
            Endpoint=endpoint_url,
            ReturnSubscriptionArn=True,
        )
        print(f"Subscription created successfully.")
        print(f"  Subscription ARN: {response.get('SubscriptionArn')}")
        return response
    except ClientError as e:
        print(f"AWS Error: {e.response['Error']['Message']}")
        return None


def list_subscriptions(topic_arn: str):
    """List existing subscriptions for a topic."""
    sns_client = boto3.client("sns")
    try:
        paginator = sns_client.get_paginator("list_subscriptions_by_topic")
        for page in paginator.paginate(TopicArn=topic_arn):
            for sub in page.get("Subscriptions", []):
                print(
                    f"  {sub['SubscriptionArn']} | "
                    f"{sub['Protocol']} | {sub['Endpoint']}"
                )
    except ClientError as e:
        print(f"AWS Error: {e.response['Error']['Message']}")


def unsubscribe(subscription_arn: str):
    """Remove an SNS subscription."""
    sns_client = boto3.client("sns")
    try:
        sns_client.unsubscribe(SubscriptionArn=subscription_arn)
        print(f"Unsubscribed: {subscription_arn}")
    except ClientError as e:
        print(f"AWS Error: {e.response['Error']['Message']}")


