        if choice == "1":
            topic_arn = input("Enter SNS Topic ARN: ").strip()
            endpoint_url = input("Enter webhook endpoint URL (https://...): ").strip()
            create_sns_subscription(topic_arn, endpoint_url)

        elif choice == "2":
            topic_arn = input("Enter SNS Topic ARN: ").strip()
            list_subscriptions(topic_arn)

        elif choice == "3":
            sub_arn = input("Enter Subscription ARN to remove: ").strip()
            unsubscribe(sub_arn)

        elif choice == "4":
            print("Exiting.")
            break

        else:
            print("Invalid option.")

        print()


